public class TestRunner {
    static int passed = 0;
    static int failed = 0;

    public static void main(String[] args) {
        EvilATM atm = new EvilATM();

        // ── Valid withdrawal ──
        check("valid 100",
              "Dispensing $100.0 | ATM logged.",
              atm.processWithdrawal("100"));

        check("valid 0.50",
              "Dispensing $0.5 | ATM logged.",
              atm.processWithdrawal("0.50"));

        // ── NumberFormatException ──
        check("word input",
              "Error: not a valid number | ATM logged.",
              atm.processWithdrawal("twenty"));

        check("empty string",
              "Error: not a valid number | ATM logged.",
              atm.processWithdrawal(""));

        // ── IllegalArgumentException: zero ──
        check("zero amount",
              "Error: Amount must be positive | ATM logged.",
              atm.processWithdrawal("0"));

        // ── IllegalArgumentException: negative ──
        check("negative amount",
              "Error: Amount must be positive | ATM logged.",
              atm.processWithdrawal("-50"));

        // ── finally always appends log ──
        String r1 = atm.processWithdrawal("200");
        String r2 = atm.processWithdrawal("bad");
        checkBool("finally on success",   true, r1.endsWith("| ATM logged."));
        checkBool("finally on exception", true, r2.endsWith("| ATM logged."));

        // ── summary ──
        System.out.println();
        int total = passed + failed;
        System.out.println((passed == total ? "PASS" : "FAIL")
            + ": " + passed + "/" + total + " tests passed");
    }

    static void check(String label, String expected, String actual) {
        if (expected.equals(actual)) {
            System.out.println("PASS: " + label); passed++;
        } else {
            System.out.println("FAIL: " + label
                + " \u2014 expected \"" + expected
                + "\" but got \"" + actual + "\""); failed++;
        }
    }
    static void checkBool(String label, boolean expected, boolean actual) {
        if (expected == actual) {
            System.out.println("PASS: " + label); passed++;
        } else {
            System.out.println("FAIL: " + label
                + " \u2014 expected " + expected + " but got " + actual); failed++;
        }
    }
}
